NoteTL;DR



git ls-files -mo --exclude-standard | grep -E 'test|bats' | xargs -i git add {}
This one-liner stages only files whose paths contain test or bats, among files that are either modified or untracked (but not ignored).

Summary








Situation
Command




See why a new file is invisible to git diff
git status --short


Make a new file visible to git diff
git add -N &lt;file&gt;


Stage the full content after reviewing
git add &lt;file&gt;


Undo git add -N (no staged content)
git reset HEAD &lt;file&gt;


Unstage a fully staged file
git restore --staged &lt;file&gt;

git-sparse-checkoutスクリプトの解説

#!/bin/bash
set -euo pipefail

usage() {
  echo "Usage: $0 -u &lt;clone_url&gt; -d &lt;target_dir&gt; -b &lt;branch&gt; -p &lt;sparse_path&gt;"
  exit 1
}

while getopts "u:d:b:p:" opt; do
  case $opt in
    u) CLONE_URL=$OPTARG ;;
    d) TARGET_DIR=$OPTARG ;;
    b) BRANCH=$OPTARG ;;
    p) SPARSE_PATH=$OPTARG ;;
    *) usage ;;
  esac
done

if [[ -z "$CLONE_URL" || -z "$TARGET_DIR" || -z "$BRANCH" || -z "$SPARSE_PATH" ]]; then
  usage
fi

git clone --filter=blob:none --no-checkout "$CLONE_URL" "$TARGET_DIR"
cd "$TARGET_DIR"
git config core.sparseCheckout true
echo -e "$SPARSE_PATH" | tr ':' '\n' &gt; .git/info/sparse-checkout
git checkout "$BRANCH"

